import sqlite3
import argparse

def initialize_db():
    conn = sqlite3.connect('phone_directory.db')
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS contacts (
            name TEXT PRIMARY KEY,
            phone TEXT NOT NULL,
            email TEXT
        )
    ''')
    conn.commit()
    return conn

def add_contact(conn, name, phone, email):
    try:
        cursor = conn.cursor()
        cursor.execute('INSERT INTO contacts VALUES (?, ?, ?)', (name, phone, email))
        conn.commit()
        print("Contact added successfully.")
    except sqlite3.IntegrityError:
        print("Error: Contact with this name already exists.")
    except Exception as e:
        print(f"Error adding contact: {str(e)}")

def update_contact(conn, name, phone=None, email=None):
    try:
        cursor = conn.cursor()
        updates = []
        params = []
        if phone:
            updates.append("phone = ?")
            params.append(phone)
        if email:
            updates.append("email = ?")
            params.append(email)
        if not updates:
            print("No updates provided.")
            return
        params.append(name)
        cursor.execute(f'UPDATE contacts SET {", ".join(updates)} WHERE name = ?', params)
        conn.commit()
        print("Contact updated successfully." if cursor.rowcount else "Contact not found.")
    except Exception as e:
        print(f"Error updating contact: {str(e)}")

def delete_contact(conn, name):
    try:
        cursor = conn.cursor()
        cursor.execute('DELETE FROM contacts WHERE name = ?', (name,))
        conn.commit()
        print("Contact deleted successfully." if cursor.rowcount else "Contact not found.")
    except Exception as e:
        print(f"Error deleting contact: {str(e)}")

def search_contacts(conn, search_term):
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM contacts WHERE name LIKE ? ORDER BY name', (f'%{search_term}%',))
        results = cursor.fetchall()
        if results:
            for name, phone, email in results:
                print(f"Name: {name}, Phone: {phone}, Email: {email}")
        else:
            print("No matching contacts found.")
    except Exception as e:
        print(f"Error searching contacts: {str(e)}")

def list_contacts(conn):
    try:
        cursor = conn.cursor()
        cursor.execute('SELECT * FROM contacts ORDER BY name')
        results = cursor.fetchall()
        if results:
            for name, phone, email in results:
                print(f"Name: {name}, Phone: {phone}, Email: {email}")
        else:
            print("No contacts in directory.")
    except Exception as e:
        print(f"Error listing contacts: {str(e)}")

def main():
    conn = initialize_db()
    parser = argparse.ArgumentParser(description="Phone Directory CLI")
    subparsers = parser.add_subparsers(dest='command')

    add_parser = subparsers.add_parser('add')
    add_parser.add_argument('-n', '--name', required=True)
    add_parser.add_argument('-p', '--phone', required=True)
    add_parser.add_argument('-e', '--email', required=True)

    update_parser = subparsers.add_parser('update')
    update_parser.add_argument('-n', '--name', required=True)
    update_parser.add_argument('-p', '--phone')
    update_parser.add_argument('-e', '--email')

    delete_parser = subparsers.add_parser('delete')
    delete_parser.add_argument('-n', '--name', required=True)

    search_parser = subparsers.add_parser('search')
    search_parser.add_argument('-s', '--search_term', required=True)

    list_parser = subparsers.add_parser('list')

    args = parser.parse_args()

    if args.command == 'add':
        add_contact(conn, args.name, args.phone, args.email)
    elif args.command == 'update':
        update_contact(conn, args.name, args.phone, args.email)
    elif args.command == 'delete':
        delete_contact(conn, args.name)
    elif args.command == 'search':
        search_contacts(conn, args.search_term)
    elif args.command == 'list':
        list_contacts(conn)
    else:
        parser.print_help()

    conn.close()

if __name__ == "__main__":
    main()
```

