import { useQuery, useApolloClient } from '@apollo/client';
import { useState } from 'react';
import { gql } from '@apollo/client';

const FILTER_PRODUCTS = gql`
  query FilterProducts($filters: ProductFilterInput!) {
    products(filter: $filters) {
      id
      name
      price
      rating
      category
    }
  }
`;

const ProductFilter = () => {
  const [selectedFilters, setSelectedFilters] = useState({
    category: '',
    minPrice: '',
    maxPrice: '',
    rating: ''
  });

  const { loading, error, data } = useQuery(FILTER_PRODUCTS, {
    variables: {
      filters: {
        category: selectedFilters.category,
        priceRange: {
          min: parseFloat(selectedFilters.minPrice),
          max: parseFloat(selectedFilters.maxPrice)
        },
        rating: parseInt(selectedFilters.rating)
      }
    }
  });

  const client = useApolloClient();

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setSelectedFilters(prev => ({
      ...prev,
      [name]: value
    }));
    client.refetchQueries({ include: [FILTER_PRODUCTS] });
  };

  return (
    <div>
      <select name="category" onChange={handleFilterChange}>
        <option value="">All Categories</option>
        <option value="electronics">Electronics</option>
        <option value="clothing">Clothing</option>
      </select>

      <input
        type="number"
        name="minPrice"
        placeholder="Min price"
        onChange={handleFilterChange}
      />
      <input
        type="number"
        name="maxPrice"
        placeholder="Max price"
        onChange={handleFilterChange}
      />

      <select name="rating" onChange={handleFilterChange}>
        <option value="">Any Rating</option>
        <option value="4">4+ Stars</option>
        <option value="3">3+ Stars</option>
      </select>

      {loading && <p>Loading...</p>}
      {error && <p>Error: {error.message}</p>}
      {data?.products?.length === 0 && <p>No products found matching your criteria</p>}

      <div>
        {data?.products?.map(product => (
          <div key={product.id}>
            <h3>{product.name}</h3>
            <p>${product.price} | {product.rating} Stars</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductFilter;
