import datetime
import requests
import redis
import json
from functools import wraps

app = Flask(__name__)
redis_client = redis.Redis(host='localhost', port=6379, db=0)
OPENWEATHERMAP_API_KEY = 'your_api_key_here'

def verify_access_token(token):
    # In real implementation, validate token with OAuth provider
    return True  # Placeholder

def require_oauth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or 'Bearer ' not in auth_header:
            return jsonify(error='Missing access token'), 403
        token = auth_header.split(' ')[1]
        if not verify_access_token(token):
            return jsonify(error='Invalid access token'), 403
        return f(*args, **kwargs)
    return decorated

@app.route('/forecast', methods=['GET'])
@require_oauth
def forecast():
    city = request.args.get('city')
    date_str = request.args.get('date')

    if not city or not date_str:
        return jsonify(error='City and date parameters are required'), 400

    try:
        date = datetime.datetime.strptime(date_str, '%Y-%m-%d').date()
    except ValueError:
        return jsonify(error='Invalid date format. Use YYYY-MM-DD'), 400

    today = datetime.date.today()
    if date < today or date > today + datetime.timedelta(days=5):
        return jsonify(error='Date must be within next 5 days'), 400

    cache_key = f'weather:{city}'
    cached = redis_client.get(cache_key)
    if cached:
        forecasts = json.loads(cached)
        for item in forecasts:
            item_date = datetime.datetime.fromtimestamp(item['dt']).date()
            if item_date == date:
                return jsonify(item)
        return jsonify(error='No data for date'), 404

    try:
        url = f'http://api.openweathermap.org/data/2.5/forecast?q={city}&appid={OPENWEATHERMAP_API_KEY}&units=metric'
        res = requests.get(url, timeout=10)
        res.raise_for_status()
        data = res.json()
    except requests.exceptions.RequestException as e:
        return jsonify(error=f'Weather API error: {str(e)}'), 500

    if 'list' not in data:
        return jsonify(error='Invalid API response'), 500

    redis_client.setex(cache_key, 7200, json.dumps(data['list']))

    for item in data['list']:
        item_date = datetime.datetime.fromtimestamp(item['dt']).date()
        if item_date == date:
            return jsonify(item)

    return jsonify(error='No forecast found'), 404

if __name__ == '__main__':
    app.run(debug=True)
