from flask import Flask, jsonify, request
from flask_jwt_extended import JWTManager, jwt_required, get_jwt_identity
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy.exc import IntegrityError
from marshmallow import Schema, fields, validate, ValidationError

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'postgresql:///mydatabase'
app.config['JWT_SECRET_KEY'] = 'super-secret'

db = SQLAlchemy(app)
jwt = JWTManager(app)
limiter = Limiter(app=app, key_func=get_remote_address)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    display_name = db.Column(db.String(30))
    email = db.Column(db.String, unique=True)
    bio = db.Column(db.String(160))

class UserSchema(Schema):
    display_name = fields.Str(validate=validate.Length(min=3, max=30), required=False)
    email = fields.Email(required=False)
    bio = fields.Str(validate=validate.Length(max=160), required=False)

@app.route('/api/v1/users/me', methods=['PATCH'])
@jwt_required()
@limiter.limit("5 per minute", key_func=lambda: get_jwt_identity())
def update_user_profile():
    current_user_id = get_jwt_identity()
    user = User.query.get(current_user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404

    try:
        data = request.get_json() or {}
    except:
        return jsonify({"error": "Invalid JSON"}), 400

    schema = UserSchema(partial=True)
    try:
        validated_data = schema.load(data)
    except ValidationError as err:
        return jsonify(err.messages), 400

    if 'email' in validated_data:
        existing_user = User.query.filter(
            User.email == validated_data['email'],
            User.id != current_user_id
        ).first()
        if existing_user:
            return jsonify({"error": "Email already exists"}), 409

    for key, value in validated_data.items():
        setattr(user, key, value)

    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return jsonify({"error": "Email conflict occurred"}), 409

    return jsonify(UserSchema().dump(user)), 200
