import { mapState, mapActions } from 'vuex'

export default {
  data: () => ({
    dialog: false,
    focus: new Date().toISOString(),
    currentTask: { id: null, title: '', description: '', priority: 'Medium', deadline: null },
    priorities: ['High', 'Medium', 'Low'],
    draggedTask: null
  }),

  computed: {
    ...mapState(['tasks']),
    calendarEvents() {
      return this.tasks.map(task => ({
        id: task.id,
        name: task.title,
        start: task.deadline,
        end: task.deadline,
        priority: task.priority
      }))
    }
  },

  methods: {
    ...mapActions(['addTask', 'updateTask', 'deleteTask']),

    required(value) {
      return !!value || 'This field is required'
    },

    openDialog() {
      this.currentTask = { id: null, title: '', description: '', priority: 'Medium', deadline: null }
      this.dialog = true
    },

    async saveTask() {
      if (this.$refs.form.validate()) {
        if (!this.currentTask.deadline) {
          alert('Deadline is required')
          return
        }

        const action = this.currentTask.id ? 'updateTask' : 'addTask'
        await this[action](this.currentTask)
        this.dialog = false
      }
    },

    getEventColor(event) {
      return {
        High: 'red',
        Medium: 'orange',
        Low: 'green'
      }[event.priority]
    },

    dragTask({ event }) {
      this.draggedTask = this.tasks.find(t => t.id === event.id)
    },

    async dropTask({ date }) {
      if (this.draggedTask) {
        await this.updateTask({
          ...this.draggedTask,
          deadline: date
        })
      }
    }
  }
}
