import { mapState, mapActions } from 'vuex'
import axios from 'axios'

export default {
  data() {
    return {
      searchQuery: '',
      users: []
    }
  },
  computed: {
    ...mapState(['currentUser', 'friends', 'sentRequests', 'receivedRequests']),
    filteredUsers() {
      return this.users.filter(user => 
        user.name.toLowerCase().includes(this.searchQuery.toLowerCase()) &&
        !this.friends.some(f => f.id === user.id) &&
        !this.sentRequests.some(sr => sr.receiver.id === user.id)
      )
    }
  },
  methods: {
    ...mapActions([
      'loadFriends',
      'loadSentRequests',
      'loadReceivedRequests',
      'addFriend',
      'removeSentRequest'
    ]),

    async sendFriendRequest() {
      const selectedUser = this.users.find(user => 
        user.name.toLowerCase() === this.searchQuery.toLowerCase()
      )
      if (selectedUser) {
        await axios.post('/api/friend-requests', { receiverId: selectedUser.id })
        this.loadSentRequests()
      }
    },

    async cancelFriendRequest(requestId) {
      await axios.delete(`/api/friend-requests/${requestId}`)
      this.removeSentRequest(requestId)
    },

    async acceptFriendRequest(requestId) {
      await axios.post(`/api/friend-requests/${requestId}/accept`)
      this.addFriend(requestId)
      this.loadReceivedRequests()
    }
  },
  async mounted() {
    this.users = (await axios.get('/api/users')).data
    this.loadFriends()
    this.loadSentRequests()
    this.loadReceivedRequests()
  }
}
</script>
