    SET_FRIENDS(state, friends) {
      state.friends = friends
    },
    SET_SENT_REQUESTS(state, requests) {
      state.sentRequests = requests
    },
    SET_RECEIVED_REQUESTS(state, requests) {
      state.receivedRequests = requests
    },
    ADD_FRIEND(state, friend) {
      state.friends.push(friend)
    },
    REMOVE_SENT_REQUEST(state, requestId) {
      state.sentRequests = state.sentRequests.filter(r => r.id !== requestId)
    }
  },
  actions: {
    async loadFriends({ commit }) {
      const response = await axios.get('/api/friends')
      commit('SET_FRIENDS', response.data)
    },
    async loadSentRequests({ commit }) {
      const response = await axios.get('/api/friend-requests/sent')
      commit('SET_SENT_REQUESTS', response.data)
    },
    async loadReceivedRequests({ commit }) {
      const response = await axios.get('/api/friend-requests/received')
      commit('SET_RECEIVED_REQUESTS', response.data)
    },
    async addFriend({ commit }, requestId) {
      const response = await axios.get(`/api/friend-requests/${requestId}`)
      commit('ADD_FRIEND', response.data.receiver)
    },
    removeSentRequest({ commit }, requestId) {
      commit('REMOVE_SENT_REQUEST', requestId)
    }
  }
})
