class TrieNode:
    def __init__(self):
        self.children = {}
        self.functions = []

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.functions.append(word)

    def autocomplete(self, prefix):
        node = self.root
        for char in prefix.lower():
            if char not in node.children:
                return []
            node = node.children[char]
        suggestions = []
        self._collect(node, suggestions)
        return suggestions

    def _collect(self, node, suggestions):
        suggestions.extend(node.functions)
        for child in node.children.values():
            self._collect(child, suggestions)

    def serialize(self):
        import json
        return json.dumps(self._serialize_node(self.root))

    def _serialize_node(self, node):
        return {
            "functions": node.functions,
            "children": {char: self._serialize_node(child) for char, child in node.children.items()}
        }

    @classmethod
    def deserialize(cls, data):
        import json
        trie = cls()
        trie.root = trie._deserialize_node(json.loads(data))
        return trie

    def _deserialize_node(self, data):
        node = TrieNode()
        node.functions = data["functions"]
        for char, child_data in data["children"].items():
            node.children[char] = self._deserialize_node(child_data)
        return node
