from flask import Flask, jsonify, request
import redis
import datetime
from functools import wraps

app = Flask(__name__)
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

def cache_response(timeout):
    def decorator(func):
        @wraps(func)
        def wrapped(*args, **kwargs):
            cache_key = f"{request.path}{request.args}"
            cached_data = redis_client.get(cache_key)
            if cached_data:
                return jsonify(cached_data.decode('utf-8'))
            response = func(*args, **kwargs)
            redis_client.setex(cache_key, timeout, response.get_data(as_text=True))
            return response
        return wrapped
    return decorator

def fetch_device_data(device_type, start_date, end_date):
    try:
        if device_type == 'fitbit':
            return [{'device': 'fitbit', 'data': 'sample_data', 'date': start_date}]
        elif device_type == 'garmin':
            return [{'device': 'garmin', 'data': 'sample_data', 'date': end_date}]
        return None
    except:
        return None

@app.route('/api/devices/data', methods=['GET'])
@cache_response(timeout=300)
def get_device_data():
    try:
        device_type = request.args.get('device_type')
        start_date = request.args.get('start_date')
        end_date = request.args.get('end_date')

        if not device_type or not start_date or not end_date:
            return jsonify({'error': 'Missing parameters'}), 400

        try:
            datetime.datetime.fromisoformat(start_date)
            datetime.datetime.fromisoformat(end_date)
        except ValueError:
            return jsonify({'error': 'Invalid date format. Use ISO format (YYYY-MM-DD)'}), 400

        device_types = device_type.split(',')
        aggregated_data = []

        for device in device_types:
            data = fetch_device_data(device, start_date, end_date)
            if data is not None:
                aggregated_data.extend(data)

        if not aggregated_data:
            return jsonify({'error': 'No data available for requested devices'}), 404

        return jsonify({'data': aggregated_data})

    except Exception as e:
        return jsonify({'error': 'Failed to fetch device data'}), 503

if __name__ == '__main__':
    app.run(debug=True)
