<?php
class FileUploadValidatorPlugin {

    private $allowedMimeTypes = ['image/jpeg', 'image/png', 'application/pdf'];
    private $maxFileSize = 5242880; // 5MB
    private $clamavSocket = '/var/run/clamav/clamd.ctl';

    public function __construct() {
        cms_add_hook('before_file_upload', [$this, 'validateFile']);
    }

    public function validateFile($file) {
        if (!$this->checkFileSize($file['size'])) {
            cms_add_error('File exceeds maximum allowed size of 5MB.');
            return false;
        }

        if (!$this->checkFileType($file['type'], $file['name'])) {
            cms_add_error('Invalid file type. Allowed formats: JPEG, PNG, PDF.');
            return false;
        }

        $scanResult = $this->scanWithClamAV($file['tmp_name']);
        if ($scanResult !== null && !$scanResult) {
            cms_add_error('File rejected: Malware detected.');
            return false;
        }

        return true;
    }

    private function checkFileSize($size) {
        return $size <= $this->maxFileSize;
    }

    private function checkFileType($mime, $filename) {
        $extension = strtolower(pathinfo($filename, PATHINFO_EXTENSION));
        $validExtension = in_array($extension, ['jpg', 'jpeg', 'png', 'pdf']);
        return $validExtension && in_array($mime, $this->allowedMimeTypes);
    }

    private function scanWithClamAV($filePath) {
        try {
            $clam = socket_create(AF_UNIX, SOCK_STREAM, 0);
            if (!@socket_connect($clam, $this->clamavSocket)) {
                cms_add_error('Security scan unavailable. Upload blocked.');
                return false;
            }

            socket_send($clam, "zINSTREAM\0", 10, 0);
            $fh = fopen($filePath, 'rb');

            while ($data = fread($fh, 4096)) {
                $size = pack('N', strlen($data));
                socket_send($clam, $size, 4, 0);
                socket_send($clam, $data, strlen($data), 0);
            }

            socket_send($clam, pack('N', 0), 4, 0);
            fclose($fh);

            $response = socket_read($clam, 4096);
            socket_close($clam);

            return strpos($response, 'OK') !== false;
        } catch (Exception $e) {
            cms_add_error('Security scan failed. Upload blocked.');
            return false;
        }
    }
}

new FileUploadValidatorPlugin();
