const Koa = require('koa');
const Router = require('@koa/router');
const bodyParser = require('koa-body');
const crypto = require('crypto');
const axios = require('axios');
const RateLimit = require('koa-ratelimit');
const Joi = require('joi');

const app = new Koa();
const router = new Router();
const db = new Map();

// In-memory store for webhooks
let webhooks = [];

// Validation schema
const webhookSchema = Joi.object({
  url: Joi.string().uri().required(),
  secretKey: Joi.string().required(),
  events: Joi.array().items(Joi.string().valid('product.created', 'product.updated', 'product.deleted')).min(1).required(),
  active: Joi.boolean().default(true)
});

// Rate limiting
app.use(RateLimit({
  driver: 'memory',
  db: db,
  duration: 900000,
  errorMessage: 'Too many requests',
  id: (ctx) => ctx.ip,
  headers: {
    remaining: 'Rate-Limit-Remaining',
    reset: 'Rate-Limit-Reset',
    total: 'Rate-Limit-Total'
  },
  max: 100
}));

// Logging middleware
app.use(async (ctx, next) => {
  const start = Date.now();
  await next();
  const ms = Date.now() - start;
  console.log(`${ctx.method} ${ctx.url} - ${ctx.status} [${ms}ms]`);
});

// Error handling
app.use(async (ctx, next) => {
  try {
    await next();
  } catch (err) {
    ctx.status = err.status || 500;
    ctx.body = { error: err.message };
    ctx.app.emit('error', err, ctx);
  }
});

// Webhook CRUD routes
router
  .get('/webhooks', (ctx) => {
    ctx.body = webhooks.filter(wh => wh.active);
  })
  .post('/webhooks', bodyParser(), async (ctx) => {
    const { error } = webhookSchema.validate(ctx.request.body);
    if (error) throw new Error(error.details[0].message);

    const webhook = {
      id: webhooks.length + 1,
      ...ctx.request.body,
      createdAt: new Date()
    };
    webhooks.push(webhook);
    ctx.status = 201;
    ctx.body = webhook;
  })
  .put('/webhooks/:id', bodyParser(), async (ctx) => {
    const id = parseInt(ctx.params.id);
    const index = webhooks.findIndex(wh => wh.id === id);
    if (index === -1) ctx.throw(404, 'Webhook not found');

    const { error } = webhookSchema.validate(ctx.request.body);
    if (error) throw new Error(error.details[0].message);

    webhooks[index] = { ...webhooks[index], ...ctx.request.body };
    ctx.body = webhooks[index];
  })
  .delete('/webhooks/:id', async (ctx) => {
    const id = parseInt(ctx.params.id);
    webhooks = webhooks.filter(wh => wh.id !== id);
    ctx.status = 204;
  });

// Event dispatcher helper
async function dispatchEvent(event, payload) {
  const relevantWebhooks = webhooks.filter(wh => 
    wh.active && wh.events.includes(event)
  );

  for (const webhook of relevantWebhooks) {
    try {
      const timestamp = Date.now();
      const signature = crypto
        .createHmac('sha256', webhook.secretKey)
        .update(`${timestamp}.${JSON.stringify(payload)}`)
        .digest('base64');

      await axios.post(webhook.url, payload, {
        headers: {
          'X-Signature': signature,
          'X-Timestamp': timestamp,
          'X-Event-Type': event
        },
        timeout: 5000
      });
    } catch (err) {
      console.error(`Webhook ${webhook.id} failed: ${err.message}`);
    }
  }
}

app.use(router.routes());
app.listen(3000, () => console.log('Webhook service running on port 3000'));
