import stripe

class StripePaymentProcessor:
    """Handles payment processing via Stripe gateway supporting multiple currencies."""

    ZERO_DECIMAL_CURRENCIES = {
        'BIF', 'CLP', 'DJF', 'GNF', 'JPY', 'KMF', 'KRW', 'MGA', 'PYG', 'RWF',
        'UGX', 'VND', 'VUV', 'XAF', 'XOF', 'XPF', 'HUF', 'TWD'
    }

    def __init__(self, api_key):
        stripe.api_key = api_key

    def process_payment(self, amount, currency, payment_method_id):
        """Process payment using Stripe API.

        Args:
            amount (float): Transaction amount in major units
            currency (str): ISO 4217 currency code
            payment_method_id (str): Stripe payment method ID

        Returns:
            bool: True if payment succeeded

        Raises:
            Exception: User-friendly error message
        """
        try:
            currency = currency.upper()
            stripe_amount = int(amount * 100) if currency not in self.ZERO_DECIMAL_CURRENCIES else int(amount)

            intent = stripe.PaymentIntent.create(
                amount=stripe_amount,
                currency=currency.lower(),
                payment_method=payment_method_id,
                confirm=True,
                automatic_payment_methods={'enabled': True}
            )

            if intent.status != 'succeeded':
                raise stripe.error.StripeError()
            return True

        except stripe.error.CardError as e:
            raise Exception(f"Card declined: {e.error.get('message')}")
        except stripe.error.InvalidRequestError as e:
            raise Exception(f"Invalid payment data: {e.error.get('message')}")
        except stripe.error.StripeError as e:
            raise Exception(f"Payment failed: {e.error.get('message') if hasattr(e, 'error') else str(e)}")
