import numpy as np

class Experiment:
    def __init__(self):
        self.parameters = {}
        self.results = {}

    def setup(self, **kwargs):
        self.parameters.update(kwargs)

    def run(self):
        v0 = self.parameters.get('initial_velocity', 0)
        angle = self.parameters.get('angle', 0)
        g = 9.81

        theta = np.radians(angle)
        t_flight = (2 * v0 * np.sin(theta)) / g
        distance = (v0**2 * np.sin(2*theta)) / g

        self.results['time_of_flight'] = t_flight
        self.results['distance'] = distance

    def compare_parameters(self, other):
        return self.parameters == other.parameters

    def compare_results(self, other, tol=1e-6):
        return (self.results.keys() == other.results.keys() and 
                all(np.allclose(self.results[k], other.results[k], atol=tol) 
                    for k in self.results))
