import { ValidatorConstraint, ValidatorConstraintInterface, registerDecorator } from 'class-validator';

@ValidatorConstraint({ async: false })
export class IsISO4217CurrencyCodeConstraint implements ValidatorConstraintInterface {
  validate(currency: string) {
    return /^[A-Z]{3}$/.test(currency);
  }

  defaultMessage() {
    return 'Invalid ISO 4217 currency code';
  }
}

export function IsISO4217CurrencyCode() {
  return function (object: Object, propertyName: string) {
    registerDecorator({
      target: object.constructor,
      propertyName: propertyName,
      constraints: [],
      validator: IsISO4217CurrencyCodeConstraint,
    });
  };
}

