export default new Vuex.Store({
  state: {
    filters: {
      brands: [],
      ratings: [],
      minPrice: 0,
      maxPrice: 0
    },
    products: []
  },
  mutations: {
    UPDATE_FILTER(state, { key, value }) {
      state.filters[key] = value;
    },
    UPDATE_PRICE_RANGE(state, [min, max]) {
      state.filters.minPrice = Math.min(min, max);
      state.filters.maxPrice = Math.max(min, max);
    },
    SET_PRODUCTS(state, products) {
      state.products = products;
      state.filters.maxPrice = Math.max(...products.map(p => p.price), 0);
    }
  },
  actions: {
    async fetchProducts({ commit }) {
      const response = await fetch('/api/products');
      const products = await response.json();
      commit('SET_PRODUCTS', products);
    }
  },
  getters: {
    filteredProducts: (state) => {
      return state.products.filter(product => {
        const brandMatch = state.filters.brands.length === 0 || 
          state.filters.brands.includes(product.brand);
        const ratingMatch = state.filters.ratings.length === 0 || 
          state.filters.ratings.some(r => product.rating >= r);
        const priceMatch = product.price >= state.filters.minPrice && 
          product.price <= state.filters.maxPrice;
        return brandMatch && ratingMatch && priceMatch;
      });
    }
  }
});
