import copy

# Initial room structure with descriptions, exits, items, and lock status
initial_rooms = {
    'great_hall': {
        'name': 'Great Hall',
        'description': 'You are in a vast hall with high ceilings. Torches line the walls.',
        'exits': {
            'north': {'room': 'dining_room', 'locked': True, 'required_item': 'key'},
            'east': {'room': 'library', 'locked': False}
        },
        'items': ['torch']
    },
    'library': {
        'name': 'Library',
        'description': 'Dusty bookshelves fill this room. A desk sits in the corner.',
        'exits': {'west': {'room': 'great_hall', 'locked': False}},
        'items': ['key']
    },
    'dining_room': {
        'name': 'Dining Room',
        'description': 'A long table with rotten food remains. Rats scurry underfoot.',
        'exits': {'south': {'room': 'great_hall', 'locked': False}},
        'items': []
    }
}

def initialize_game():
    """Initialize a new game state with default values and deep copy of rooms."""
    return {
        'current_room': 'great_hall',
        'inventory': [],
        'rooms': copy.deepcopy(initial_rooms)
    }

def save_game(game_state, filename='save.json'):
    """Save the current game state to a JSON file."""
    try:
        with open(filename, 'w') as f:
            json.dump(game_state, f, indent=4)
        print("Game saved successfully.")
    except Exception as e:
        print(f"Error saving game: {e}")

def load_game(filename='save.json'):
    """Load a saved game state from a JSON file."""
    try:
        with open(filename, 'r') as f:
            loaded_state = json.load(f)
        print("Game loaded successfully.")
        return loaded_state
    except FileNotFoundError:
        print("No saved game found.")
        return None
    except Exception as e:
        print(f"Error loading game: {e}")
        return None

def handle_command(command, game_state):
    """Parse and execute player commands."""
    command_parts = command.lower().split()
    if not command_parts:
        print("Invalid command. Type 'help' for instructions.")
        return

    action = command_parts[0]
    current_room = game_state['current_room']
    rooms = game_state['rooms']
    inventory = game_state['inventory']

    if action == 'move' and len(command_parts) > 1:
        direction = command_parts[1]
        exits = rooms[current_room]['exits']
        if direction in exits:
            exit_info = exits[direction]
            if exit_info.get('locked', False):
                required_item = exit_info.get('required_item', 'unknown item')
                print(f"The {direction} exit is locked. You need a {required_item}.")
            else:
                game_state['current_room'] = exit_info['room']
                print(f"You move {direction} to the {rooms[exit_info['room']]['name']}.")
        else:
            print("You can't go that way.")

    elif action == 'take' and len(command_parts) > 1:
        item = command_parts[1]
        if item in rooms[current_room]['items']:
            rooms[current_room]['items'].remove(item)
            inventory.append(item)
            print(f"You took the {item}.")
        else:
            print("That item isn't here.")

    elif action == 'use' and len(command_parts) > 1:
        item = command_parts[1]
        if item not in inventory:
            print("You don't have that item.")
            return
        exits = rooms[current_room]['exits']
        unlocked = False
        for direction, exit_info in exits.items():
            if exit_info.get('locked') and exit_info.get('required_item') == item:
                exit_info['locked'] = False
                inventory.remove(item)
                print(f"You unlocked the {direction} exit with the {item}.")
                unlocked = True
        if not unlocked:
            print("There's nothing to use that on here.")

    elif action == 'save':
        save_game(game_state)

    elif action == 'load':
        loaded_state = load_game()
        if loaded_state:
            game_state.clear()
            game_state.update(loaded_state)

    elif action == 'inventory':
        print("Inventory:", ", ".join(inventory) if inventory else "Empty")

    elif action == 'look':
        room = rooms[current_room]
        print(f"\n{room['name']}\n{room['description']}")
        print("Items here:", ", ".join(room['items']) if room['items'] else "None")
        print("Exits:", ", ".join(room['exits'].keys()))

    elif action == 'help':
        print("Commands: move <direction>, take <item>, use <item>, save, load, inventory, look, quit")

    else:
        print("Invalid command. Type 'help' for instructions.")

def main():
    """Main game loop handling player input and game state."""
    print("Welcome to the Castle Adventure Game! Type 'help' for instructions.")
    game_state = initialize_game()

    while True:
        current_room = game_state['current_room']
        room_data = game_state['rooms'][current_room]
        print(f"\n{room_data['name']}\n{room_data['description']}")
        print("Items here:", ", ".join(room_data['items']) if room_data['items'] else "No items")
        print("Exits:", ", ".join(room_data['exits'].keys()))

        command = input("\nWhat would you like to do? ").strip()
        if command == 'quit':
            print("Thanks for playing!")
            break
        handle_command(command, game_state)

if __name__ == "__main__":
    main()
