const express = require('express');
const app = express();

const WINDOW_DURATION = 5 * 60 * 1000;
const MAX_REQUESTS_PER_WINDOW = 100;
const BLOCK_DURATION = 60 * 60 * 1000;

const rateLimits = new Map();
const blockedIps = new Map();

app.use((req, res, next) => {
    const ip = req.ip;
    const now = Date.now();

    if (blockedIps.has(ip)) {
        if (blockedIps.get(ip) > now) {
            console.log(`Blocked IP: ${ip}`);
            return res.sendStatus(403);
        }
        blockedIps.delete(ip);
    }

    let entry = rateLimits.get(ip);
    if (entry) {
        if (now >= entry.windowStart + WINDOW_DURATION) {
            entry.count = 1;
            entry.windowStart = now;
        } else {
            entry.count++;
        }
    } else {
        entry = { count: 1, windowStart: now };
        rateLimits.set(ip, entry);
    }

    if (entry.count > MAX_REQUESTS_PER_WINDOW) {
        blockedIps.set(ip, now + BLOCK_DURATION);
        rateLimits.delete(ip);
        console.log(`Blocked IP: ${ip}`);
        return res.sendStatus(403);
    }

    next();
});

app.get('/admin/blocked-ips', (req, res) => {
    const blocked = Array.from(blockedIps.entries()).map(([ip, expiry]) => ({
        ip,
        expires: new Date(expiry).toISOString()
    }));
    res.json(blocked);
});

app.delete('/admin/blocked-ips/:ip', (req, res) => {
    const ip = req.params.ip;
    const deleted = blockedIps.delete(ip);
    res.status(deleted ? 200 : 404).json({ success: deleted });
});

module.exports = app;
