// CurrencyConversionRequest.cs
using System.ComponentModel.DataAnnotations;

public class CurrencyConversionRequest
{
    [Required]
    [RegularExpression(@"^[A-Z]{3}$")]
    public string FromCurrency { get; set; }

    [Required]
    [RegularExpression(@"^[A-Z]{3}$")]
    public string ToCurrency { get; set; }

    [Required]
    [Range(0.01, double.MaxValue)]
    public decimal Amount { get; set; }
}

// ConversionResponse.cs
public class ConversionResponse
{
    public string FromCurrency { get; set; }
    public string ToCurrency { get; set; }
    public decimal ExchangeRate { get; set; }
    public decimal OriginalAmount { get; set; }
    public decimal ConvertedAmount { get; set; }
    public DateTime Timestamp { get; set; }
}

// ErrorResponse.cs
public class ErrorResponse
{
    public string Error { get; set; }
    public object Details { get; set; }
}

// ConversionController.cs
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using System;
using System.Net.Http;
using System.Threading.Tasks;
using Polly;
using System.Net;

[ApiController]
[Route("[controller]")]
public class ConvertController : ControllerBase
{
    private readonly IHttpClientFactory _clientFactory;
    private readonly IMemoryCache _cache;
    private readonly ILogger<ConvertController> _logger;

    public ConvertController(
        IHttpClientFactory clientFactory,
        IMemoryCache cache,
        ILogger<ConvertController> logger)
    {
        _clientFactory = clientFactory;
        _cache = cache;
        _logger = logger;
    }

    [HttpGet]
    [ServiceFilter(typeof(ApiKeyAuthFilter))]
    [ProducesResponseType(typeof(ConversionResponse), 200)]
    [ProducesResponseType(typeof(ErrorResponse), 400)]
    [ProducesResponseType(typeof(ErrorResponse), 401)]
    [ProducesResponseType(typeof(ErrorResponse), 503)]
    public async Task<IActionResult> Convert([FromQuery] CurrencyConversionRequest request)
    {
        var cacheKey = $"{request.FromCurrency}-{request.ToCurrency}";
        if (!_cache.TryGetValue(cacheKey, out decimal rate))
        {
            var client = _clientFactory.CreateClient("ExchangeRateClient");
            var policy = Policy<HttpResponseMessage>
                .Handle<HttpRequestException>()
                .OrResult(r => !r.IsSuccessStatusCode)
                .WaitAndRetryAsync(3, retryAttempt => 
                    TimeSpan.FromSeconds(Math.Pow(2, retryAttempt)));

            try
            {
                var response = await policy.ExecuteAsync(() => 
                    client.GetAsync($"rates?base={request.FromCurrency}"));

                if (!response.IsSuccessStatusCode)
                    return StatusCode(503, new ErrorResponse { 
                        Error = "Rate service unavailable", 
                        Details = response.ReasonPhrase 
                    });

                var content = await response.Content.ReadAsAsync<ExchangeRateApiResponse>();
                rate = content.Rates[request.ToCurrency];
                _cache.Set(cacheKey, rate, TimeSpan.FromMinutes(5));
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Exchange rate service failure");
                return StatusCode(503, new ErrorResponse { 
                    Error = "Rate service unavailable", 
                    Details = ex.Message 
                });
            }
        }

        var convertedAmount = request.Amount * rate;
        return Ok(new ConversionResponse
        {
            FromCurrency = request.FromCurrency,
            ToCurrency = request.ToCurrency,
            ExchangeRate = rate,
            OriginalAmount = request.Amount,
            ConvertedAmount = convertedAmount,
            Timestamp = DateTime.UtcNow
        });
    }
}

// ApiKeyAuthFilter.cs
using Microsoft.AspNetCore.Mvc.Filters;
using Microsoft.Extensions.Configuration;

public class ApiKeyAuthFilter : IAsyncActionFilter
{
    private readonly IConfiguration _configuration;

    public ApiKeyAuthFilter(IConfiguration configuration)
    {
        _configuration = configuration;
    }

    public async Task OnActionExecutionAsync(ActionExecutingContext context, ActionExecutionDelegate next)
    {
        if (!context.HttpContext.Request.Headers.TryGetValue("X-Api-Key", out var apiKey))
        {
            context.Result = new UnauthorizedObjectResult(new ErrorResponse { 
                Error = "Unauthorized", 
                Details = "Missing API key" 
            });
            return;
        }

        var validKey = _configuration["ApiKey"];
        if (apiKey != validKey)
        {
            context.Result = new UnauthorizedObjectResult(new ErrorResponse { 
                Error = "Unauthorized", 
                Details = "Invalid API key" 
            });
            return;
        }

        await next();
    }
}

