# views.py
from django.shortcuts import render, redirect
from django.contrib.auth.decorators import login_required
from django.contrib import messages
from .models import Subscription
from .forms import SubscribeForm, UnsubscribeForm

@login_required
def manage_subscription(request):
    if request.method == 'POST':
        if 'subscribe' in request.POST:
            form = SubscribeForm(request.POST)
            if form.is_valid():
                Subscription.objects.update_or_create(
                    user=request.user,
                    defaults={'subscription_status': True}
                )
                messages.success(request, 'Successfully subscribed!')
            else:
                messages.error(request, 'Please confirm your subscription')

        elif 'unsubscribe' in request.POST:
            form = UnsubscribeForm(request.POST)
            if form.is_valid():
                Subscription.objects.update_or_create(
                    user=request.user,
                    defaults={'subscription_status': False}
                )
                messages.success(request, 'Successfully unsubscribed!')
            else:
                messages.error(request, 'Please confirm your unsubscription')

        return redirect('manage_subscription')

    subscribe_form = SubscribeForm()
    unsubscribe_form = UnsubscribeForm()
    try:
        subscription = Subscription.objects.get(user=request.user)
    except Subscription.DoesNotExist:
        subscription = None

    return render(request, 'subscription.html', {
        'subscribe_form': subscribe_form,
        'unsubscribe_form': unsubscribe_form,
        'subscription': subscription
    })
