const express = require('express');
const passport = require('passport');
const session = require('express-session');
const helmet = require('helmet');
const bcrypt = require('bcrypt');
const mysql = require('mysql2/promise');
const RateLimit = require('express-rate-limit');
const https = require('https');
const fs = require('fs');
const { Strategy: GoogleStrategy } = require('passport-google-oauth20');
const { Strategy: FacebookStrategy } = require('passport-facebook');
const { Strategy: GithubStrategy } = require('passport-github2');

const app = express();

// Database setup
const pool = mysql.createPool({
  host: process.env.DB_HOST,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  database: process.env.DB_NAME,
  waitForConnections: true,
});

async function initializeDatabase() {
  await pool.execute(`
    CREATE TABLE IF NOT EXISTS users (
      id INT AUTO_INCREMENT PRIMARY KEY,
      email VARCHAR(255) UNIQUE,
      password VARCHAR(255),
      provider VARCHAR(50),
      providerId VARCHAR(255),
      createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    )
  `);
}
initializeDatabase();

// Session configuration
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true }
}));

// Security middleware
app.use(helmet());
app.use(express.json());

// Rate limiting
const authLimiter = RateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  message: 'Too many attempts, please try again later.'
});
app.use('/auth/login', authLimiter);
app.use('/auth/register', authLimiter);

// Passport setup
passport.serializeUser((user, done) => done(null, user.id));
passport.deserializeUser(async (id, done) => {
  const [user] = await pool.execute('SELECT * FROM users WHERE id = ?', [id]);
  done(null, user[0]);
});

// OAuth Strategies
passport.use(new GoogleStrategy({
  clientID: process.env.GOOGLE_CLIENT_ID,
  clientSecret: process.env.GOOGLE_CLIENT_SECRET,
  callbackURL: '/auth/google/callback'
}, async (accessToken, refreshToken, profile, done) => {
  handleOAuthLogin(profile, 'google', done);
}));

passport.use(new FacebookStrategy({
  clientID: process.env.FACEBOOK_APP_ID,
  clientSecret: process.env.FACEBOOK_APP_SECRET,
  callbackURL: '/auth/facebook/callback',
  profileFields: ['id', 'emails']
}, async (accessToken, refreshToken, profile, done) => {
  handleOAuthLogin(profile, 'facebook', done);
}));

passport.use(new GithubStrategy({
  clientID: process.env.GITHUB_CLIENT_ID,
  clientSecret: process.env.GITHUB_CLIENT_SECRET,
  callbackURL: '/auth/github/callback'
}, async (accessToken, refreshToken, profile, done) => {
  handleOAuthLogin(profile, 'github', done);
}));

async function handleOAuthLogin(profile, provider, done) {
  const email = profile.emails?.[0]?.value;
  const [user] = await pool.execute(
    'SELECT * FROM users WHERE provider = ? AND providerId = ?',
    [provider, profile.id]
  );
  if (user.length) return done(null, user[0]);
  const newUser = await pool.execute(
    'INSERT INTO users (email, provider, providerId) VALUES (?, ?, ?)',
    [email, provider, profile.id]
  );
  done(null, { id: newUser[0].insertId, email, provider });
}

// Routes
app.use(passport.initialize());
app.use(passport.session());

app.get('/auth/google', passport.authenticate('google', { scope: ['profile', 'email'] }));
app.get('/auth/facebook', passport.authenticate('facebook', { scope: ['email'] }));
app.get('/auth/github', passport.authenticate('github', { scope: ['user:email'] }));

app.post('/auth/login', async (req, res) => {
  const [users] = await pool.execute('SELECT * FROM users WHERE email = ?', [req.body.email]);
  const user = users[0];
  if (user && bcrypt.compareSync(req.body.password, user.password)) {
    req.login(user, () => res.status(200).json({ message: 'Logged in' }));
  } else {
    res.status(401).json({ message: 'Invalid credentials' });
  }
});

app.post('/auth/register', async (req, res) => {
  const hashedPassword = bcrypt.hashSync(req.body.password, 10);
  await pool.execute(
    'INSERT INTO users (email, password) VALUES (?, ?)',
    [req.body.email, hashedPassword]
  );
  res.status(201).json({ message: 'User created' });
});

// HTTPS setup
const server = https.createServer({
  key: fs.readFileSync('./localhost.key'),
  cert: fs.readFileSync('./localhost.crt')
}, app).listen(443);

module.exports = server;

